"""Table 1: auto-generated encoders overview LaTeX.

Paper binding: Section 3.3 / Table 1 of the paper.

Generates a LaTeX `tabular` listing every entry in
src.encoders._REGISTRY, with columns:
    - Modality
    - Encoder display name
    - HuggingFace source or safetensors path
    - Feature dimension d

The generator instantiates each loader briefly to read the
`feature_dim` and `modality` from the returned LoadedEncoder. This is
cheap because every loader is already memoized inside HuggingFace's
cache on disk.

Usage:
    python -m src.experiments.tbl1_encoders \
        --latex-path paper/tables/tbl1_encoders.tex
"""
from __future__ import annotations
import argparse
import gc
from pathlib import Path

from src.encoders import get_encoder, list_encoders


# Mapping from registry name to a (display_name, source, modality_label)
# tuple. Keeps the generator independent of how HF paths are stored.
_DISPLAY: dict[str, tuple[str, str, str]] = {
    "dinov2_small":       ("DINOv2-Small",           r"\texttt{facebook/dinov2-small}",              "Vision"),
    "dinov2_base":        ("DINOv2-Base",            r"\texttt{facebook/dinov2-base}",               "Vision"),
    "dinov2_large":       ("DINOv2-Large",           r"\texttt{facebook/dinov2-large}",              "Vision"),
    "clip_l_vision":      ("CLIP ViT-L/14 (vision)", r"\texttt{openai/clip-vit-large-patch14}",       "Vision"),
    "clip_l_text":        ("CLIP ViT-L/14 (text)",   r"\texttt{openai/clip-vit-large-patch14}",       "Language"),
    "siglip_base_vision": ("SigLIP-Base/16 (vision)",r"\texttt{google/siglip-base-patch16-224}",      "Vision"),
    "siglip_base_text":   ("SigLIP-Base/16 (text)",  r"\texttt{google/siglip-base-patch16-224}",      "Language"),
    "mpnet":              ("all-mpnet-base-v2",      r"\texttt{sentence-transformers/all-mpnet-base-v2}", "Language"),
    "sparsh_dino_base":   ("Sparsh-DINO-Base",       r"\texttt{facebook/sparsh-dino-base} (6-ch)",    "Tactile"),
    "sparsh_ijepa_base":  ("Sparsh-IJEPA-Base",      r"\texttt{facebook/sparsh-ijepa-base} (6-ch)",   "Tactile"),
}


def main():
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--latex-path", type=str,
                        default="paper/tables/tbl1_encoders.tex")
    parser.add_argument("--skip-load", action="store_true",
                        help="Do not instantiate loaders (use _DISPLAY only). "
                             "Faster, but won't verify feature_dim at runtime.")
    args = parser.parse_args()

    rows = []
    for name in list_encoders():
        if name not in _DISPLAY:
            display, source, modality_label = (name, name, "?")
        else:
            display, source, modality_label = _DISPLAY[name]

        if args.skip_load:
            feature_dim = {
                "dinov2_small": 384,
                "dinov2_base": 768,
                "dinov2_large": 1024,
            }.get(name, 768)
        else:
            print(f"[tbl1] probing {name} ...", flush=True)
            enc = get_encoder(name)
            feature_dim = enc.feature_dim
            del enc
            gc.collect()

        rows.append((modality_label, display, source, feature_dim))

    # Sort by modality (Vision, Language, Tactile), then by name
    modality_order = {"Vision": 0, "Language": 1, "Tactile": 2, "?": 3}
    rows.sort(key=lambda r: (modality_order.get(r[0], 99), r[1]))

    latex_lines = [
        "% Auto-generated by src/experiments/tbl1_encoders.py",
        "% Paper binding: Section 3.3 / Tbl. 1 of the paper",
        r"\begin{table}[t]",
        r"\centering",
        r"\caption{Encoders used in this work. "
        r"Vision and language encoders are standard pretrained "
        r"HuggingFace transformers; tactile encoders are Sparsh variants "
        r"from facebookresearch/sparsh (Higuera et al., 2024), loaded via "
        r"reverse-engineered state dict from safetensors and served with "
        r"6-channel inputs formed by same-frame duplication of TVL's "
        r"static tactile images (see \S\ref{sec:sparsh-sensitivity}).}",
        r"\label{tab:encoders}",
        r"\begin{tabular}{llll}",
        r"\toprule",
        r"Modality & Encoder & Source & $d$ \\",
        r"\midrule",
    ]
    prev_modality = None
    for modality_label, display, source, feature_dim in rows:
        if prev_modality and prev_modality != modality_label:
            latex_lines.append(r"\midrule")
        latex_lines.append(
            f"{modality_label} & {display} & {source} & {feature_dim} \\\\"
        )
        prev_modality = modality_label
    latex_lines.append(r"\bottomrule")
    latex_lines.append(r"\end{tabular}")
    latex_lines.append(r"\end{table}")

    out_path = Path(args.latex_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with out_path.open("w") as f:
        f.write("\n".join(latex_lines) + "\n")
    print(f"[tbl1] wrote {out_path} ({len(rows)} rows)")


if __name__ == "__main__":
    main()
